import unittest
from interfaces import Encoder
from impl import Base64Encoder

class TestInterface(unittest.TestCase):
    def test_inheritance(self):
        self.assertTrue(issubclass(Base64Encoder, Encoder))
        enc = Base64Encoder()
        self.assertEqual(enc.encode(b'A'), 'QQ==')

if __name__ == '__main__':
    unittest.main()
